module TopModule #(parameter WIDTH = 8, parameter DEPTH = 16)(
    input wclk, rclk, rstn, winc, rinc,
    input [WIDTH-1:0] wdata,
    output reg wfull, rempty,
    output [WIDTH-1:0] rdata
);
// BEGIN: Declare control logic
// WRITE LOGIC
//   - Write pointer logic
reg [$clog2(DEPTH)-1:0] waddr_bin;
always @(posedge wclk or negedge rstn) begin
    if (~rstn) begin
        waddr_bin <= 0;
    end else if (winc & ~wfull) begin
        waddr_bin <= waddr_bin + 1;
    end
end
reg [$clog2(DEPTH)-1:0] wptr;
always @(posedge wclk or negedge rstn) begin
    if (~rstn) begin
        wptr <= 0;
    end else if (winc & ~wfull) begin
        wptr <= wptr ^ (wptr >> 1);
    end
end
//   - Write pointer buffer logic
reg [$clog2(DEPTH)-1:0] wptr_buff;
always @(posedge wclk or negedge rstn) begin
    if (~rstn) begin
        wptr_buff <= 0;
    end else begin
        wptr_buff <= wptr;
    end
end
// END: Declare control logic
// BEGIN: Declare memory
//   - Read pointer logic
reg [$clog2(DEPTH)-1:0] raddr_bin;
always @(posedge rclk or negedge rstn) begin
    if (~rstn) begin
        raddr_bin <= 0;
    end else if (rinc & ~rempty) begin
        raddr_bin <= raddr_bin + 1;
    end
end
reg [$clog2(DEPTH)-1:0] rptr;
always @(posedge rclk or negedge rstn) begin
    if (~rstn) begin
        rptr <= 0;
    end else if (rinc & ~rempty) begin
        rptr <= rptr ^ (rptr >> 1);
    end
end
//     - Read pointer buffer logic
reg [$clog2(DEPTH)-1:0] rptr_buff;
always @(posedge rclk or negedge rstn) begin
    if (~rstn) begin
        rptr_buff <= 0;
    end else begin
        rptr_buff <= rptr;
    end
end
// END: Declare memory
// BEGIN: Memory
//   - Full signal logic
reg wfull;
always @(posedge wclk or negedge rstn) begin
    if (~rstn) begin
        wfull <= 0;
    end else if (wptr == ~rptr_buff & wptr[$clog2(DEPTH)] != rptr_buff[$clog2(DEPTH)]) begin
        wfull <= 1;
    end else begin
        wfull <= 0;
    end
end
//   - Empty signal logic
reg rempty;
always @(posedge rclk or negedge rstn) begin
    if (~rstn) begin
        rempty <= 0;
    end else if (rptr == wptr_buff & rptr[$clog2(DEPTH)] != wptr_buff[$clog2(DEPTH)]) begin
        rempty <= 1;
    end else begin
        rempty <= 0;
    end
end
// END: Memory
// BEGIN: Data flow
//   - Dual-port RAM instantiation
wire [WIDTH-1:0] rdata;
dual_port_RAM #(.DEPTH(DEPTH), .WIDTH(WIDTH)) dual_port_RAM_inst (
    .wclk(wclk),
    .wenc(winc),
    .waddr(waddr_bin),
    .wdata(wdata),
    .rclk(rclk),
    .renc(rinc),
    .raddr(raddr_bin),
    .rdata(rdata)
);
// END: Data flow
// BEGIN: Output logic
//   - Read data output
assign rdata = rdata;
// END: Output logic
endmodule
